sp_widget.client_script:
api.controller = function ($scope, $rootScope, spUtil) {
//------------------------------------------------------------------------------------------------------------------------
// WIDGET BASE: FIELDS
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
//------------------------------------------------------------------------------------------------------------------------
	//spUtil.recordWatch($scope, $scope.data.table, "sys_id=" + $scope.data.sys_id); 
	var c = this;

	var onSaveUpdate = $scope.$on('sp.form.record.updated', refreshWidget);



	$rootScope.$on('$TaskerTaskList.click', function(e, parms) {
		c.data.table = parms.table;
		c.data.sys_id = parms.sys_id;
		refreshWidget();
	});
	$rootScope.$on('$sp.list.click', function(e, parms) {
		c.data.sys_id = parms.sys_id;
		c.data.table = parms.table;
		refreshWidget();
	});
	$rootScope.$on('$taskerTabbedForm.drillDownList.click', function(e, parms) {
		c.data.sys_id = parms.sys_id;
		c.data.table = parms.table;
		refreshWidget();
	});



	function refreshWidget(evt,arg) {
		$scope.server.update();
	}
};

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES
// WIDGET BASE: FIELDS
//------------------------------------------------------------------------------------------------------------------------
// KT - TLV - STRY0057360 - Macro Widget: Updated to 101
// 2.5.13: 08.12.20 | KT | SEQ | STRY0076826: SEQ - Task Details page - WAITING State displays on State Flow banner, 
//											Task List View  and Summary Card
// 2.7.0 | 2021-08-23 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
//                                         Round 2. In HTML, renamed .bg-waiting to .Waiting to use existing CSS Selectors.
//                                         Added HTML to display State Count for Draft. Pulled KT's comments out to Serverscript.
//                                         In CSS, Removed State styling .bg-*; use existing Tasker State CSS Include. 
//                                         In Server script, added code to get State Count for Draft. Added ending semicolon.
//                                         In Client controller, changed to use "api.controller = function() {};", added the semicolon
//                                         Changes made in HTML, CSS, Serverscript and Client controller.
// 2.8 | 2022-05-17 | raj  |  STRY0120403 - Delegation Layout- Add buttons to filter "This Task" and "All Descendant Tasks"
//                                      changes in server script to allow multiple controls to set the filter level
//                                      Fixed a problem with incomplete and cancelled tasks not showing correctly
// 2.8 | 2022-05-17 | raj  |  STRY0122619 - Existing Task Form- Subtask percentage updated to be "Whole Numbers Only"
//                                      changes in server script to remove decimal
// 2.8 | 2022-07-16 | raj  |  STRY0120159 - Task Form- New Icons to Filter "This Task or All Descendants"
//                                      changes in Server Script and HTML
// 2.8 | 2022-09-02 | mmcc | DFCT0011213 - In Tree Bi-Fold, in Subtask tab, Task Progress Bar PUSHES content off on certain monitor sizes
//                                      In HTML, add margin bottom 0 to class with progress
//                                      In CSS, delete all lines
//                                      Changes made in HTML and CSS.
// 
//------------------------------------------------------------------------------------------------------------------------

(function(data) {
	data.pickupMsg = gs.getMessage(options.pickup_msg);
	data.page = $sp.getParameter("id");

	var gr;

	data.sys_id = (input || {}).sys_id || (options || {}).sys_id || undefined;
	data.table = (input || {}).table || (options || {}).table || undefined;
	if(data.sys_id){
		gr = new GlideRecordSecure(data.table);
		if(!gr.get(data.sys_id)){
			return;
		}		
	} else {
		gr = $sp.getRecord();
		if (gr == null)
			return;
	}


	data.canRead = gr.canRead();
	if (!data.canRead)
		return;

	data.tableLabel = gr.getLabel();
	data.table = gr.getTableName();
	data.sys_id = gr.getUniqueValue();
	data.showDesc=(input || {}).showDesc || (options || {}).showDesc || false;
	data.dynamic_tree = $sp.getParameter("dynamic_tree"); // KT - TLV - STRY0057360 - Macro Widget
	convertToBool(["showDesc", "dynamic_tree"]);
	var showDescendantRollUp = data.showDesc || data.dynamic_tree;


	data.page = $sp.getParameter("id");

	data.nDraft = 0;
	data.nWaiting = 0;
	data.nUnassigned = 0;
	data.nAssigned = 0;
	data.nAccepted = 0;
	data.nRejected = 0;
	data.nWorkScheduled = 0;
	data.nInProgress = 0;
	data.nInReview = 0;
	data.nRework =0;
	data.nCompleted = 0;
	data.nCancelled = 0;
	data.nIncompleted = 0;

	/*
	-5	Awaiting Assignment
	1	Awaiting Acceptance
	10	Assignment Accepted
	11	Assignment Rejected
	12	Work Scheduled
	13	Work in Progress
	14	In Review
	15	Rework
	3	Closed Complete
	4	Closed Incomplete
	7	Closed Skipped
	*/


	data.calchaschildren = gr.getValue('calchaschildren');

	if(data.calchaschildren > 0){
		// STRY0120403
		data.nDraft = getStateCount(data.table, data.sys_id, -6, showDescendantRollUp);
		data.nWaiting = getStateCount(data.table, data.sys_id, -3, showDescendantRollUp);
		data.nUnassigned = getStateCount(data.table, data.sys_id, -5, showDescendantRollUp);
		data.nAssigned = getStateCount(data.table, data.sys_id, 1, showDescendantRollUp);
		data.nAccepted = getStateCount(data.table, data.sys_id, 10, showDescendantRollUp);
		data.nRejected = getStateCount(data.table, data.sys_id, 11, showDescendantRollUp);
		data.nWorkScheduled = getStateCount(data.table, data.sys_id, 12, showDescendantRollUp);
		data.nInProgress = getStateCount(data.table, data.sys_id, 13, showDescendantRollUp);
		data.nInReview = getStateCount(data.table, data.sys_id, 14, showDescendantRollUp);
		data.nRework = getStateCount(data.table, data.sys_id, 15, showDescendantRollUp);
		data.nCompleted = getStateCount(data.table, data.sys_id, 3, showDescendantRollUp);
		data.nIncompleted = getStateCount(data.table, data.sys_id, 4, showDescendantRollUp);
		data.nCanceled = getStateCount(data.table, data.sys_id, 7, showDescendantRollUp);
	}

	//-------------------------------------------------------------------------------------------------------------------
	function getStateCount(table, sys_id, statevalue, showDescendantRollUp) {
		// STRY0120159 - updated to account for percent total going over 100
		var oPercent = {};
		var nTotal = 0;
		var nSubTotal = 0;
		var grTaskInstance;
		var grTaskInstanceSubTotal;
		var percentage = 0;
		var filter = 'u_all_ancestors_tasksLIKE'+ sys_id;

		grTaskInstance = new GlideAggregate(table);
		// STRY0120403
		if (showDescendantRollUp) {
			grTaskInstance.addQuery('u_all_ancestors_tasks', 'CONTAINS', sys_id); 
		} else{
			grTaskInstance.addQuery('parent',sys_id); // KT - TLV - STRY0057360 - Macro Widget
		}

		grTaskInstance.addAggregate('COUNT');
		grTaskInstance.query();

		if(grTaskInstance.next()) {
			nTotal = grTaskInstance.getAggregate('COUNT');
		}

		grTaskInstanceSubTotal = new GlideAggregate(table);
		// STRY0120403
		if (showDescendantRollUp){
			grTaskInstanceSubTotal.addQuery('u_all_ancestors_tasks', 'CONTAINS', sys_id); 
		} else {
			grTaskInstanceSubTotal.addQuery('parent',sys_id); // KT - TLV - STRY0057360 - Macro Widget
		}

		grTaskInstanceSubTotal.addQuery('state',statevalue);
		grTaskInstanceSubTotal.addAggregate('COUNT');
		grTaskInstanceSubTotal.query();


		if(grTaskInstanceSubTotal.next()) {
			nSubTotal = grTaskInstanceSubTotal.getAggregate('COUNT');
			oPercent.value = nSubTotal * 100 / nTotal;
			oPercent.diplayValue = percentage = (nSubTotal * 100 / nTotal).toFixed(0); //<!-- // KT - TLV - STRY0057360 - Macro Widget: Updated to 2 -->
		}
		return oPercent;
	}
	// 2.7.1 | 2021-12-10 | mmcc | STRY0115408 - Long text needs to be shortened and have an ellipsis
	function convertToBool(names) {
		names.forEach(function(name) {
			data[name] = data[name] == true || data[name] == 'true';
		});
	}
})(data);
